import React, { createContext, useState, useEffect, useContext } from 'react';
import { getMT5Status } from '../services/api';

const MT5Context = createContext();

export const MT5Provider = ({ children }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [accountInfo, setAccountInfo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState({
    connected: false,
    terminal: null,
    account: null,
    server: null,
    balance: 0.0,
    equity: 0.0,
    symbol_ready: false,
    candles_ready: false,
    last_error: null,
    checks: {
      terminal_running: false,
      mt5_initialized: false,
      login_success: false,
      account_info: false,
      terminal_info: false,
      symbol_exists: false,
      candles_retrievable: false
    }
  });

  useEffect(() => {
    checkConnection();
    // Start periodic status checking
    const intervalId = setInterval(checkConnection, 5000);
    return () => clearInterval(intervalId);
  }, []);

  const checkConnection = async () => {
    try {
      const status = await getMT5Status();
      setConnectionStatus(status);
      setIsConnected(status.connected);
      
      if (status.connected && status.account_info) {
        setAccountInfo(status.account_info);
      } else {
        setAccountInfo(null);
      }
    } catch (error) {
      console.error('Failed to check MT5 connection:', error);
      setConnectionStatus(prev => ({
        ...prev,
        connected: false,
        last_error: error.message
      }));
      setIsConnected(false);
      setAccountInfo(null);
    } finally {
      setLoading(false);
    }
  };

  const connectMT5 = (login, password, server) => {
    // Actual connection is done via api, then we check status
    setTimeout(checkConnection, 1000);
  };

  const disconnectMT5 = () => {
    setIsConnected(false);
    setAccountInfo(null);
    setConnectionStatus(prev => ({
      ...prev,
      connected: false,
      symbol_ready: false,
      candles_ready: false
    }));
  };

  const isFullyConnected = () => {
    return connectionStatus.connected && 
           connectionStatus.symbol_ready && 
           connectionStatus.candles_ready;
  };

  return (
    <MT5Context.Provider
      value={{
        isConnected,
        accountInfo,
        loading,
        connectionStatus,
        checkConnection,
        connectMT5,
        disconnectMT5,
        setIsConnected,
        setAccountInfo,
        isFullyConnected
      }}
    >
      {children}
    </MT5Context.Provider>
  );
};

export const useMT5 = () => useContext(MT5Context);
